namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int RecipeCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh mozzarella and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                AverageRating = 4.5, RatingCount = 12
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and spices, simmer 15 minutes.", "Stir in cream and add chicken.", "Serve over basmati rice."],
                AverageRating = 4.8, RatingCount = 25
            },
            new Recipe
            {
                Id = 3, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa."],
                AverageRating = 4.2, RatingCount = 18
            },
            new Recipe
            {
                Id = 4, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Classic Roman pasta with eggs, cheese, and pancetta.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps = ["Cook spaghetti in salted boiling water.", "Crisp pancetta in a skillet.", "Whisk eggs with grated pecorino and pepper.", "Drain pasta, reserving some water.", "Toss hot pasta with pancetta, then egg mixture.", "Serve immediately with extra cheese."],
                AverageRating = 4.7, RatingCount = 30
            },
            new Recipe
            {
                Id = 5, Title = "Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with shrimp and peanuts.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Lime", "Fish sauce", "Tamarind paste", "Sugar"],
                Steps = ["Soak rice noodles in warm water 30 minutes.", "Make sauce: mix tamarind, fish sauce, and sugar.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in the same pan.", "Add drained noodles and sauce, toss.", "Add shrimp, sprouts, and peanuts. Serve with lime."],
                AverageRating = 4.6, RatingCount = 15
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, chunky guacamole with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, jalapeño, and tomato.", "Add lime juice and chopped cilantro.", "Season with salt to taste.", "Serve with tortilla chips."],
                AverageRating = 4.4, RatingCount = 22
            },
            new Recipe
            {
                Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Chewy, golden cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla", "Flour", "Baking soda", "Salt", "Chocolate chips"],
                Steps = ["Preheat oven to 375°F.", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour, baking soda, and salt.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheet, bake 9-11 minutes."],
                AverageRating = 4.9, RatingCount = 40
            },
            new Recipe
            {
                Id = 8, Title = "Green Curry", Category = "Thai",
                Description = "Fragrant coconut curry with vegetables and chicken.",
                Ingredients = ["Green curry paste", "Coconut milk", "Chicken thigh", "Bamboo shoots", "Thai basil", "Bell pepper", "Fish sauce", "Sugar"],
                Steps = ["Heat coconut cream in a pot until oil separates.", "Fry curry paste for 2 minutes.", "Add sliced chicken, cook 5 minutes.", "Pour in coconut milk and bamboo shoots.", "Simmer 10 minutes, season with fish sauce and sugar.", "Stir in basil and bell pepper. Serve over rice."],
                AverageRating = 4.3, RatingCount = 11
            },
        ];
    }

    public List<RecipeCategory> GetCategories()
    {
        lock (_lock)
        {
            return _recipes
                .GroupBy(r => r.Category)
                .Select(g => new RecipeCategory
                {
                    Name = g.Key,
                    Icon = GetCategoryIcon(g.Key),
                    Description = GetCategoryDescription(g.Key),
                    RecipeCount = g.Count()
                })
                .OrderBy(c => c.Name)
                .ToList();
        }
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetRecipeById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is null || stars is < 1 or > 5) return;

            var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        lock (_lock)
        {
            recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
            _recipes.Add(recipe);
        }
    }

    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Thai" => "🍜",
        "Desserts" => "🍪",
        _ => "🍽️"
    };

    private static string GetCategoryDescription(string category) => category switch
    {
        "Italian" => "Classic pasta, pizza, and Mediterranean flavors",
        "Indian" => "Rich curries, aromatic spices, and vibrant dishes",
        "Mexican" => "Bold flavors with fresh salsas and tortillas",
        "Thai" => "Balanced sweet, sour, salty, and spicy cuisine",
        "Desserts" => "Sweet treats and baked goods",
        _ => "Delicious recipes to explore"
    };
}

