@page "/recipes/{Category}"
@using RecipeHub.Services
@using RecipeHub.Models

@inject RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

<h1 class="mb-4">@Category Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in _recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">
                            <a href="recipe/@recipe.Id" class="text-decoration-none">@recipe.Title</a>
                        </h4>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                                <span class="text-muted ms-1">(@recipe.AverageRating)</span>
                            </span>
                            <span class="text-muted small">@recipe.RatingCount ratings</span>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Models

@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeHub</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@_recipe.Title - RecipeHub</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="recipes/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1 class="mb-2">@_recipe.Title</h1>
            <p class="lead text-muted">@_recipe.Description</p>

            <StarRating RecipeId="@_recipe.Id" @rendermode="InteractiveServer" />

            <hr />

            <h3 class="mt-4">🧾 Ingredients</h3>
            <ul class="list-group list-group-flush mb-4">
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>

            <h3>📝 Steps</h3>
            <ol class="list-group list-group-numbered list-group-flush">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            <div class="card shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">Recipe Info</h5>
                    <dl>
                        <dt>Category</dt>
                        <dd><a href="recipes/@_recipe.Category">@_recipe.Category</a></dd>
                        <dt>Ingredients</dt>
                        <dd>@_recipe.Ingredients.Count items</dd>
                        <dt>Steps</dt>
                        <dd>@_recipe.Steps.Count steps</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services

@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2 fw-semibold">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star-rating @(star <= _hovered ? "hovered" : "") @(star <= _selected ? "selected" : "")"
              role="button"
              @onmouseover="() => _hovered = star"
              @onmouseout="() => _hovered = 0"
              @onclick="() => SubmitRating(star)"
              title="Rate @star stars">
            @(star <= (_hovered > 0 ? _hovered : _selected) ? "★" : "☆")
        </span>
    }

    @if (_submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int _hovered;
    private int _selected;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        _selected = stars;
        _submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@using RecipeHub.Models

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit Recipe - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1 class="mb-4">Submit a Recipe</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_title</strong>" has been added to the @_category category.</p>
        <a href="recipes/@_category" class="btn btn-primary">View Category</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="@this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="_title" required placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="_category">
                        <option value="">Select a category...</option>
                        <option value="Italian">Italian</option>
                        <option value="Indian">Indian</option>
                        <option value="Mexican">Mexican</option>
                        <option value="Thai">Thai</option>
                        <option value="Desserts">Desserts</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="description" class="form-label">Description</label>
                    <InputTextArea id="description" class="form-control" @bind-Value="_description" rows="2" placeholder="A short description of your recipe" />
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" @bind-Value="_ingredientsText" rows="5" placeholder="One ingredient per line" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" class="form-control" @bind-Value="_stepsText" rows="5" placeholder="One step per line" />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                <button type="submit" class="btn btn-primary btn-lg" disabled="@(!IsValid)">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _description = string.Empty;
    private string _ingredientsText = string.Empty;
    private string _stepsText = string.Empty;
    private bool _submitted;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(_title) &&
        !string.IsNullOrWhiteSpace(_category) &&
        !string.IsNullOrWhiteSpace(_ingredientsText) &&
        !string.IsNullOrWhiteSpace(_stepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var recipe = new Recipe
        {
            Title = _title.Trim(),
            Category = _category,
            Description = _description.Trim(),
            Ingredients = _ingredientsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = _stepsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        _submitted = true;
    }
}

